function twoPointersTemplate(arr) {
  let left = 0;
  let right = arr.length - 1;
  while (left < right) {
    // Process elements at left and right
    if (condition) {
      left++;
    } else {
      right--;
    }
  }
}

function slidingWindowTemplate(arr) {
  let start = 0;
  let currentSum = 0;
  for (let end = 0; end < arr.length; end++) {
    currentSum += arr[end];
    while (shrinkCondition) {
      currentSum -= arr[start];
      start++;
    }
  }
}

function fastSlowPointerTemplate(head) {
  let slow = head;
  let fast = head;
  while (fast !== null && fast.next !== null) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) {
      return true; // Cycle detected
    }
  }
  return false;
}

function mergeIntervalsTemplate(intervals) {
  intervals.sort((a, b) => a[0] - b[0]);
  const merged = [intervals[0]];
  for (let i = 1; i < intervals.length; i++) {
    let lastMerged = merged[merged.length - 1];
    let curr = intervals[i];
    if (curr[0] <= lastMerged[1]) {
      lastMerged[1] = Math.max(lastMerged[1], curr[1]);
    } else {
      merged.push(curr);
    }
  }
  return merged;
}

function topologicalSortKahn(numNodes, edges) {
  const adj = Array.from({length: numNodes}, () => []);
  const inDegree = Array(numNodes).fill(0);
  for (let [u, v] of edges) {
    adj[u].push(v);
    inDegree[v]++;
  }
  const queue = [];
  for (let i = 0; i < numNodes; i++) {
    if (inDegree[i] === 0) queue.push(i);
  }
  const order = [];
  while (queue.length > 0) {
    let u = queue.shift();
    order.push(u);
    for (let v of adj[u]) {
      inDegree[v]--;
      if (inDegree[v] === 0) queue.push(v);
    }
  }
  return order.length === numNodes ? order : [];
}
